<script setup lang="ts">
useHead({ title: "Vendas" })
useLegacyKiwifyInteractions()
const { sales, getSaleById } = useSales()
const route = useRoute()
const salesSearch = ref('')
const activeSalesTab = computed(() => String(route.query.tab || 'all'))
const filtersOpen = ref(false)
const currentPage = ref(1)
const pageSize = 10
const periodFilter = ref('all')
const currencyFilter = ref('all')
const typeFilter = ref('all')
const productFilter = ref('all')
const offerFilter = ref('all')
const paymentMethodFilters = ref<string[]>([])
const statusFilters = ref<string[]>([])
const subscriptionFilters = ref<string[]>([])
const salesMockIds = [
  'f87bbc92-be55-4fc0-9d21-a56a49b672de',
  'cb24b6ec-1bf5-46a2-8606-9ab4ee1a6b88',
  'd4161e70-32d9-4324-a527-c0f93c5f2c9b',
  '7dfa4c4b-4d69-42f1-807c-5dc43ced79fc'
]
const liveSales = computed(() => sales.value.filter((sale) => !salesMockIds.includes(sale.id)))
const parseSaleValue = (value: string) => {
  const normalized = value.replace(/[^\d,.-]/g, '').replace(/\./g, '').replace(',', '.')
  return Number(normalized || 0)
}
const normalizeFilterValue = (value?: string) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
const parseSaleDate = (createdAt: string) => {
  const [datePart] = String(createdAt || '').split(' ')
  const [day, month, year] = datePart.split('/').map(Number)
  if (!day || !month || !year) return null
  return new Date(year, month - 1, day)
}
const matchesPeriodFilter = (createdAt: string) => {
  if (periodFilter.value === 'all') return true
  const saleDate = parseSaleDate(createdAt)
  if (!saleDate) return false
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  const saleDay = new Date(saleDate)
  saleDay.setHours(0, 0, 0, 0)
  if (periodFilter.value === 'today') return saleDay.getTime() === today.getTime()
  const days = Number(periodFilter.value)
  if (!Number.isFinite(days)) return true
  const start = new Date(today)
  start.setDate(start.getDate() - days + 1)
  return saleDay >= start
}
const matchesPaymentMethodFilter = (method: string) => {
  if (!paymentMethodFilters.value.length) return true
  const normalized = normalizeFilterValue(method)
  return paymentMethodFilters.value.some((filter) => {
    if (filter === 'credit_card') return normalized.includes('cartao') || normalized.includes('credito')
    if (filter === 'card_pix') return normalized.includes('cartao') && normalized.includes('pix')
    if (filter === 'boleto') return normalized.includes('boleto')
    if (filter === 'pix') return normalized.includes('pix')
    return true
  })
}
const matchesStatusFilter = (status: string) => {
  if (!statusFilters.value.length) return true
  const normalized = normalizeFilterValue(status)
  return statusFilters.value.some((filter) => {
    if (filter === 'paid') return normalized.includes('pago') || normalized.includes('approved')
    if (filter === 'refused') return normalized.includes('recus')
    if (filter === 'waiting_payment') return normalized.includes('aguard')
    if (filter === 'refunded') return normalized.includes('reembolso')
    if (filter === 'chargedback') return normalized.includes('chargeback')
    if (filter === 'refund_requested') return normalized.includes('pendente')
    if (filter === 'authorized') return normalized.includes('autoriz')
    return true
  })
}
const productOptions = computed(() => Array.from(new Set(liveSales.value.map((sale) => sale.product).filter(Boolean))).sort())
const offerOptions = computed(() => Array.from(new Set(liveSales.value.map((sale) => sale.offerId).filter(Boolean) as string[])).sort())
const periodFilterLabel = computed(() => ({
  all: 'Tempo todo',
  today: 'Hoje',
  '7': 'Últimos 7 dias',
  '30': 'Últimos 30 dias',
  '90': 'Últimos 90 dias'
})[periodFilter.value] || 'Tempo todo')
const currencyFilterLabel = computed(() => currencyFilter.value === 'all' ? 'Todas' : currencyFilter.value)
const typeFilterLabel = computed(() => typeFilter.value === 'all' ? 'Todos' : 'Venda')
const productFilterLabel = computed(() => productFilter.value === 'all' ? 'Todos os produtos' : productFilter.value)
const offerFilterLabel = computed(() => offerFilter.value === 'all' ? 'Todos' : offerFilter.value)
const paymentMethodValues = ['credit_card', 'card_pix', 'boleto', 'pix']
const statusValues = ['paid', 'refused', 'waiting_payment', 'refunded', 'chargedback', 'refund_requested', 'authorized']
const toggleAllPaymentMethods = () => {
  paymentMethodFilters.value = paymentMethodFilters.value.length === paymentMethodValues.length ? [] : [...paymentMethodValues]
}
const toggleAllStatuses = () => {
  statusFilters.value = statusFilters.value.length === statusValues.length ? [] : [...statusValues]
}
const clearSalesFilters = () => {
  periodFilter.value = 'all'
  currencyFilter.value = 'all'
  typeFilter.value = 'all'
  productFilter.value = 'all'
  offerFilter.value = 'all'
  paymentMethodFilters.value = []
  statusFilters.value = []
  subscriptionFilters.value = []
}
const filteredSales = computed(() => {
  const term = salesSearch.value.trim().toLowerCase()
  return liveSales.value
    .filter((sale) => activeSalesTab.value === 'all' || sale.status === 'Pago')
    .filter((sale) => matchesPeriodFilter(sale.createdAt))
    .filter((sale) => currencyFilter.value === 'all' || sale.value.includes(currencyFilter.value))
    .filter(() => typeFilter.value === 'all' || typeFilter.value === 'sale')
    .filter((sale) => productFilter.value === 'all' || sale.product === productFilter.value)
    .filter((sale) => offerFilter.value === 'all' || sale.offerId === offerFilter.value)
    .filter((sale) => matchesPaymentMethodFilter(sale.method))
    .filter((sale) => matchesStatusFilter(sale.status))
    .filter((sale) => {
      if (!term) return true
      return [sale.product, sale.customer, sale.customerEmail, sale.status, sale.method]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(term))
    })
})
const salesCountLabel = computed(() => new Intl.NumberFormat('pt-BR').format(filteredSales.value.length))
const salesTotalLabel = computed(() => {
  const total = filteredSales.value.reduce((sum, sale) => sum + parseSaleValue(sale.value), 0)
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(total)
})
const pageCount = computed(() => Math.max(1, Math.ceil(filteredSales.value.length / pageSize)))
const pageCountLabel = computed(() => new Intl.NumberFormat('pt-BR').format(pageCount.value))
const pageNumbers = computed(() => Array.from({ length: pageCount.value }, (_, index) => index + 1).slice(0, 5))
const paginatedSales = computed(() => {
  const start = (currentPage.value - 1) * pageSize
  return filteredSales.value.slice(start, start + pageSize)
})
const setSalesPage = (page: number) => {
  currentPage.value = Math.min(Math.max(page, 1), pageCount.value)
}
const selectedSaleId = computed(() => String(route.query.id || ''))
const selectedSale = computed(() => getSaleById(selectedSaleId.value))
const saleTabClass = (tab: string) => [
  'py-1 font-medium static text-sm leading-5 rounded-md cursor-pointer px-3',
  activeSalesTab.value === tab ? 'text-indigo-700' : 'hover:text-gray-700 focus:outline-none'
]
const saleStatusBadgeClass = (status: string) => {
  const normalized = normalizeFilterValue(status)
  if (normalized.includes('aguard') || normalized.includes('pending')) return 'bg-yellow-100 text-yellow-800'
  if (normalized.includes('recus') || normalized.includes('falhou') || normalized.includes('cancel')) return 'bg-red-100 text-red-800'
  if (normalized.includes('reembolso')) return 'bg-gray-100 text-gray-800'
  return 'bg-green-100 text-green-800'
}
const selectSalesTab = (event: Event) => {
  navigateTo(`/sales?tab=${(event.target as HTMLSelectElement).value}`)
}

const syncSaleDetailPanel = () => {
  const panels = Array.from(document.querySelectorAll<HTMLElement>('section > .w-screen.z-50.fixed.h-full.top-0.right-0'))
  const detailPanel = panels.find((panel) => panel.textContent?.includes('Ver detalhes'))
  if (detailPanel) {
    detailPanel.style.display = selectedSale.value ? 'flex' : 'none'
    const sale = selectedSale.value
    if (sale) {
      const rows = Array.from(detailPanel.querySelectorAll<HTMLElement>('.grid.grid-cols-3.gap-2'))
      const setRow = (label: string, value: string) => {
        const row = rows.find((item) => item.querySelector('h3')?.textContent?.trim() === label)
        const target = row?.querySelector<HTMLElement>('.col-span-2 > div')
        if (target) target.textContent = value
      }
      setRow('ID da venda', sale.id.toUpperCase())
      setRow('Status', sale.status)
      setRow('Tipo', 'Venda')
      setRow('Valor líquido', sale.value)
      setRow('Produto', sale.product)
      setRow('Método de pagamento', sale.method)
      setRow('Parcelas', sale.method === 'Pix' ? '1' : '1x')
      setRow('Data da criação', sale.createdAt)
    }
  }
}

onMounted(syncSaleDetailPanel)
watch(() => route.query.id, syncSaleDetailPanel)
watch([filteredSales, activeSalesTab], () => {
  currentPage.value = 1
})
</script>

